// table schema generated by introspection
import { timestamps } from '@app/common';
import { USER_ROLES, UserRole } from '@app/modules/users/types/user.role.enum';
import {
  mysqlTable,
  int,
  varchar,
  mysqlEnum,
  datetime,
  date,
  text,
} from 'drizzle-orm/mysql-core';

export const userSchema = mysqlTable('users', {
  id: int().autoincrement().primaryKey(),
  email: varchar({ length: 255 }).notNull().unique(),
  password: varchar({ length: 255 }).notNull(),
  name: varchar({ length: 255 }).notNull(),
  authProvider: varchar('auth_provider', { length: 255 }).notNull(),
  profilePicture: varchar('profile_picture', { length: 255 }),
  role: mysqlEnum('role', USER_ROLES).notNull().default(UserRole.USER),
  resetPasswordToken: varchar('reset_password_token', { length: 64 }),
  resetPasswordTokenExpiresAt: datetime('reset_password_token_expires_at'),
  phoneNumber: varchar('phone_number', { length: 255 }),
  date_of_birth: date('date_of_birth'),
  memo: text('memo'),
  ...timestamps,
});
